INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('red_flags','dvt_pe',ARRAY['جلطة','تورم الساق','ألم الساق','صعوبة التنفس','انسداد رئوي'],'جلطة الأوردة العميقة / الانسداد الرئوي',E'## 🚨 جلطة الأوردة العميقة / الانسداد الرئوي\n\n### الأعراض\n- تورم مفاجئ في ساق واحدة\n- ألم في الربلة يزداد عند المشي\n- احمرار ودفء موضعي\n- ضيق تنفس مفاجئ (انسداد رئوي)\n\n### ⚠️ اذهب للطوارئ فوراً\n- ضيق تنفس مفاجئ + ألم في الصدر\n- تورم ساق + سرعة نبض\n- إغماء أو دوخة شديدة','ar','NICE/BTS',10,true),
('red_flags','dka',ARRAY['سكري','حموضة','غيبوبة سكر','كيتون','جفاف شديد','تنفس سريع'],'الحماض الكيتوني السكري',E'## 🚨 الحماض الكيتوني السكري (DKA)\n\n### الأعراض\n- عطش شديد + تبول كثير\n- غثيان وقيء\n- ألم بطن\n- تنفس سريع وعميق (كوسماول)\n- رائحة فاكهة من الفم\n- تشوش ذهني\n\n### ⚠️ طوارئ فورية\n- سكر الدم > 250 + أعراض\n- محاليل وريدية + أنسولين\n- مراقبة البوتاسيوم','ar','ADA',10,true),
('red_flags','ectopic_pregnancy',ARRAY['حمل خارج الرحم','نزيف مهبلي','ألم بطن','تأخر دورة','إغماء'],'الحمل خارج الرحم',E'## 🚨 الحمل خارج الرحم\n\n### الأعراض\n- تأخر الدورة الشهرية\n- ألم أسفل البطن (جانب واحد)\n- نزيف مهبلي غير طبيعي\n- ألم في الكتف (تهيج الحجاب الحاجز)\n- دوخة أو إغماء\n\n### ⚠️ طوارئ جراحية\n- قد يسبب نزيف داخلي مميت\n- فحص حمل + سونار مهبلي\n- قد يحتاج جراحة فورية','ar','RCOG',10,true),
('red_flags','acute_abdomen',ARRAY['ألم بطن حاد','بطن حاد','التهاب زائدة','انسداد أمعاء','ثقب معدة'],'البطن الحاد',E'## 🚨 البطن الحاد\n\n### أسباب خطيرة\n- التهاب الزائدة الدودية\n- انسداد الأمعاء\n- ثقب القرحة المعدية\n- التهاب المرارة الحاد\n- تمزق الطحال\n\n### ⚠️ اطلب المساعدة فوراً\n- ألم بطن شديد + تصلب البطن\n- قيء + عدم خروج غازات\n- حمى + ألم بطن متزايد\n- نبض سريع + هبوط ضغط','ar','WHO',10,true),
('red_flags','meningitis',ARRAY['التهاب سحايا','صداع شديد','تصلب رقبة','حمى','طفح جلدي','فقدان وعي'],'التهاب السحايا',E'## 🚨 التهاب السحايا\n\n### الأعراض\n- حمى شديدة\n- صداع حاد\n- تصلب الرقبة\n- حساسية للضوء\n- غثيان وقيء\n- طفح جلدي لا يختفي بالضغط\n\n### عند الأطفال\n- بكاء مستمر\n- انتفاخ اليافوخ\n- رفض الرضاعة\n- خمول شديد\n\n### ⚠️ طوارئ فورية\n- مضادات حيوية وريدية خلال ساعة\n- لا تنتظر نتائج الفحوصات','ar','WHO',10,true),
('red_flags','suicidal_ideation',ARRAY['انتحار','رغبة بالموت','أفكار سلبية','اكتئاب شديد','إيذاء النفس'],'الأفكار الانتحارية',E'## 🚨 الأفكار الانتحارية\n\n### علامات الخطر\n- التحدث عن الرغبة بالموت\n- الشعور باليأس الشديد\n- الانسحاب من الأنشطة\n- التخلص من الممتلكات\n- تغيرات مفاجئة في السلوك\n\n### ⚠️ تصرف فوراً\n- لا تترك الشخص وحده\n- أبعد الأدوات الخطرة\n- اطلب مساعدة نفسية متخصصة\n- خط مساعدة نفسية\n- قد يحتاج دخول مستشفى','ar','WHO',10,true),
('red_flags','hypertensive_crisis',ARRAY['ضغط مرتفع','أزمة ضغط','صداع شديد','نزيف أنف','ضبابية الرؤية'],'أزمة ارتفاع الضغط',E'## 🚨 أزمة ارتفاع ضغط الدم\n\n### التعريف\n- ضغط انقباضي > 180 أو انبساطي > 120\n\n### أعراض الطوارئ\n- صداع شديد مفاجئ\n- ألم في الصدر\n- ضيق تنفس\n- ضبابية الرؤية\n- نزيف أنفي شديد\n- تشوش أو غثيان\n\n### ⚠️ تصرف فوراً\n- اذهب للطوارئ فوراً\n- لا تتناول أدوية إضافية بدون إشراف\n- قد يسبب سكتة دماغية أو قلبية','ar','AHA',10,true),
('red_flags','hypoglycemia',ARRAY['هبوط السكر','نقص سكر','رجفة','تعرق','إغماء','سكري'],'هبوط سكر الدم',E'## 🚨 هبوط سكر الدم\n\n### الأعراض\n- رجفة وتعرق\n- خفقان القلب\n- جوع شديد\n- تشوش ذهني\n- ضعف وعدم تركيز\n- فقدان الوعي (حالات شديدة)\n\n### ⚠️ علاج فوري\n- واعي: 15-20 غم سكر سريع (عصير، حلوى)\n- أعد الفحص بعد 15 دقيقة\n- فاقد الوعي: جلوكاجون عضلي + طوارئ\n- لا تعطِ أي شيء بالفم لفاقد الوعي','ar','ADA',10,true),
('red_flags','acute_asthma',ARRAY['ربو حاد','ضيق تنفس','صفير','نوبة ربو','بخاخ'],'نوبة الربو الحادة',E'## 🚨 نوبة الربو الحادة\n\n### درجات الشدة\n- خفيفة: يستطيع التحدث بجمل كاملة\n- متوسطة: يتحدث بكلمات فقط\n- شديدة: لا يستطيع التحدث\n- مهددة للحياة: صدر صامت، زرقة\n\n### ⚠️ علاج فوري\n- سالبوتامول 4-8 بخات كل 20 دقيقة\n- بريدنيزولون 40-50 ملغ فموي\n- أكسجين إذا SpO2 < 92%\n- اذهب للطوارئ إذا لم يتحسن','ar','BTS/GINA',10,true),
('red_flags','testicular_torsion',ARRAY['التواء الخصية','ألم خصية','تورم الخصية','مراهق'],'التواء الخصية',E'## 🚨 التواء الخصية\n\n### الأعراض\n- ألم مفاجئ شديد في الخصية\n- تورم واحمرار\n- غثيان وقيء\n- الخصية مرتفعة عن الطبيعي\n\n### ⚠️ طوارئ جراحية\n- يجب الجراحة خلال 6 ساعات\n- التأخير يسبب فقدان الخصية\n- أكثر شيوعاً عند المراهقين\n- لا تنتظر - اذهب للطوارئ فوراً','ar','EAU',10,true),
('red_flags','placental_abruption',ARRAY['انفصال المشيمة','نزيف حمل','ألم بطن','رحم متصلب','صدمة'],'انفصال المشيمة',E'## 🚨 انفصال المشيمة\n\n### الأعراض\n- نزيف مهبلي (قد يكون مخفي)\n- ألم بطن شديد ومستمر\n- رحم متصلب ومؤلم\n- انخفاض حركة الجنين\n\n### ⚠️ طوارئ توليدية\n- يهدد حياة الأم والجنين\n- محاليل وريدية + نقل دم\n- مراقبة نبض الجنين\n- ولادة طارئة عادة','ar','RCOG',10,true),
('red_flags','acute_glaucoma',ARRAY['جلوكوما حادة','ألم عين شديد','هالات ضوئية','فقدان بصر','عين حمراء'],'الجلوكوما الحادة',E'## 🚨 الجلوكوما الحادة (ارتفاع ضغط العين)\n\n### الأعراض\n- ألم شديد في العين\n- رؤية هالات حول الأضواء\n- احمرار العين\n- ضبابية الرؤية المفاجئة\n- غثيان وقيء\n- بؤبؤ متسع وثابت\n\n### ⚠️ طوارئ عينية\n- خطر فقدان البصر الدائم\n- قطرات خافضة للضغط فوراً\n- ليزر أو جراحة عاجلة','ar','AAO',10,true),
('red_flags','aortic_dissection',ARRAY['تسلخ الأبهر','ألم صدر ممزق','ضغط مرتفع','ألم ظهر حاد'],'تسلخ الشريان الأبهر',E'## 🚨 تسلخ الشريان الأبهر\n\n### الأعراض\n- ألم صدري ممزق مفاجئ\n- ينتشر للظهر بين الكتفين\n- اختلاف الضغط بين الذراعين\n- نبض ضعيف أو مفقود\n\n### ⚠️ أخطر طوارئ القلب\n- نسبة الوفاة 1% كل ساعة بدون علاج\n- خفض الضغط فوراً\n- CT مع صبغة للتشخيص\n- جراحة طارئة عادة','ar','AHA/ESC',10,true),
('red_flags','tension_pneumothorax',ARRAY['استرواح صدري','انهيار رئة','صعوبة تنفس شديدة','إصابة صدر'],'الاسترواح الصدري الضاغط',E'## 🚨 الاسترواح الصدري الضاغط\n\n### الأعراض\n- ضيق تنفس شديد ومتصاعد\n- ألم صدري في جهة واحدة\n- انتفاخ أوردة الرقبة\n- انحراف القصبة الهوائية\n- غياب أصوات التنفس في جهة\n\n### ⚠️ إجراء منقذ للحياة\n- إبرة تخفيف ضغط فوري\n- الفراغ الوربي الثاني خط منتصف الترقوة\n- ثم أنبوب صدري','ar','ATLS',10,true),
('red_flags','status_epilepticus',ARRAY['نوبة صرع مستمرة','تشنجات','صرع','فقدان وعي'],'حالة الصرع المستمرة',E'## 🚨 حالة الصرع المستمرة\n\n### التعريف\n- نوبة صرع > 5 دقائق\n- أو نوبتان بدون استعادة الوعي بينهما\n\n### ⚠️ علاج فوري\n- حماية المريض من الإصابة\n- لا تضع شيئاً في الفم\n- ديازيبام 10 ملغ شرجي أو وريدي\n- أو ميدازولام أنفي/عضلي\n- إذا استمرت: فينيتوين وريدي\n- مجرى هوائي + أكسجين','ar','ILAE',10,true),
('red_flags','sepsis',ARRAY['تسمم دم','إنتان','حمى شديدة','هبوط ضغط','تسارع قلب'],'الإنتان (تسمم الدم)',E'## 🚨 الإنتان (تسمم الدم)\n\n### معايير qSOFA\n- ضغط انقباضي ≤ 100\n- معدل تنفس ≥ 22\n- تغير الوعي\n\n### أعراض\n- حمى أو انخفاض حرارة\n- تسارع القلب\n- تنفس سريع\n- تشوش ذهني\n- جلد مبقع أو بارد\n\n### ⚠️ بروتوكول الساعة الأولى\n- زراعة دم قبل المضادات\n- مضادات حيوية واسعة وريدية\n- محاليل 30 مل/كغ\n- قياس اللاكتات','ar','Sepsis-3',10,true),
('red_flags','stroke',ARRAY['سكتة دماغية','شلل نصفي','ثقل لسان','ضعف مفاجئ','فقدان بصر'],'السكتة الدماغية',E'## 🚨 السكتة الدماغية\n\n### علامات FAST\n- **F** تدلي الوجه\n- **A** ضعف الذراع\n- **S** صعوبة الكلام\n- **T** وقت الاتصال بالطوارئ\n\n### ⚠️ كل دقيقة مهمة\n- يجب الوصول للمستشفى خلال 4.5 ساعات\n- CT مخ لاستبعاد النزيف\n- دواء مذيب للجلطة (tPA) إذا مؤهل\n- لا تعطِ أسبرين قبل CT','ar','AHA/ASA',10,true),
('red_flags','acute_mi',ARRAY['نوبة قلبية','احتشاء','ألم صدر','ذبحة','ضيق تنفس'],'النوبة القلبية',E'## 🚨 النوبة القلبية (احتشاء عضلة القلب)\n\n### الأعراض\n- ألم ضاغط في الصدر > 20 دقيقة\n- ينتشر للذراع الأيسر أو الفك\n- تعرق بارد\n- ضيق تنفس\n- غثيان\n\n### ⚠️ تصرف فوراً\n- اتصل بالطوارئ\n- أسبرين 300 ملغ يمضغ\n- نيتروجليسرين تحت اللسان\n- لا تقُد السيارة بنفسك','ar','AHA/ESC',10,true),
('red_flags','anaphylaxis',ARRAY['حساسية مفرطة','تأق','تورم الحلق','ضيق تنفس','طفح'],'التأق (الحساسية المفرطة)',E'## 🚨 التأق (الحساسية المفرطة)\n\n### الأعراض\n- تورم الوجه والشفتين واللسان\n- صعوبة التنفس أو البلع\n- طفح جلدي منتشر (شرى)\n- هبوط ضغط الدم\n- دوخة أو إغماء\n\n### ⚠️ علاج فوري\n- أدرينالين (إبينفرين) عضلي 0.5 ملغ\n- اتصل بالطوارئ\n- وضعية الاستلقاء مع رفع الساقين\n- أكسجين ومحاليل وريدية','ar','WAO',10,true),
('red_flags','severe_bleeding',ARRAY['نزيف شديد','نزيف حاد','صدمة نزفية','فقدان دم'],'النزيف الشديد',E'## 🚨 النزيف الشديد\n\n### علامات الصدمة النزفية\n- نبض سريع وضعيف\n- هبوط ضغط الدم\n- شحوب وتعرق بارد\n- تشوش ذهني\n- قلة البول\n\n### ⚠️ إسعاف فوري\n- ضغط مباشر على مكان النزيف\n- رفع الطرف المصاب\n- لا تزيل الضمادة الأولى\n- محاليل وريدية + نقل دم\n- جراحة إذا لم يتوقف','ar','ATLS',10,true),
('red_flags','cord_prolapse',ARRAY['تدلي الحبل السري','طوارئ ولادة','نبض جنين','ولادة طارئة'],'تدلي الحبل السري',E'## 🚨 تدلي الحبل السري\n\n### الأعراض\n- الإحساس بشيء في المهبل بعد نزول الماء\n- انخفاض مفاجئ في نبض الجنين\n\n### ⚠️ أخطر طوارئ الولادة\n- اركعي بوضعية الركبة-الصدر\n- لا تحاولي دفع الحبل للداخل\n- اتصلي بالطوارئ فوراً\n- ولادة قيصرية طارئة خلال دقائق\n- ادفعي رأس الجنين للأعلى','ar','RCOG',10,true),
('red_flags','acute_abdomen_child',ARRAY['ألم بطن أطفال','انغلاف','التهاب زائدة أطفال','براز دموي'],'البطن الحاد عند الأطفال',E'## 🚨 البطن الحاد عند الأطفال\n\n### أسباب حسب العمر\n- رضيع: انغلاف الأمعاء، فتق مختنق\n- طفل: التهاب الزائدة، الإمساك الشديد\n- مراهق: التهاب الزائدة، حمل خارج الرحم (بنات)\n\n### علامات الخطر\n- بكاء شديد متقطع + براز أحمر (انغلاف)\n- ألم يبدأ حول السرة وينتقل لليمين\n- قيء أخضر (انسداد)\n\n### ⚠️ اطلب المساعدة\n- لا تعطِ مسكنات قبل التقييم\n- سونار + أشعة بطن','ar','WHO/IMCI',10,true),
('red_flags','poisoning',ARRAY['تسمم','ابتلاع مادة سامة','جرعة زائدة','تسمم أطفال'],'التسمم والجرعة الزائدة',E'## 🚨 التسمم والجرعة الزائدة\n\n### خطوات فورية\n- لا تحاول إحداث القيء\n- اتصل بمركز السموم\n- احتفظ بالعبوة أو المادة\n- سجل الوقت والكمية\n\n### حالات شائعة\n- باراسيتامول: الترياق N-acetylcysteine خلال 8 ساعات\n- مبيدات حشرية: أتروبين + أوكسيم\n- مواد كاوية: لا تحدث القيء أبداً\n\n### ⚠️ اذهب للطوارئ إذا\n- فقدان الوعي\n- صعوبة التنفس\n- تشنجات\n- أي ابتلاع مادة كاوية','ar','WHO',10,true),
('red_flags','pulmonary_edema',ARRAY['وذمة رئوية','ماء على الرئة','ضيق تنفس شديد','فشل قلب حاد'],'الوذمة الرئوية الحادة',E'## 🚨 الوذمة الرئوية الحادة\n\n### الأعراض\n- ضيق تنفس شديد ومفاجئ\n- يسوء عند الاستلقاء\n- بلغم وردي رغوي\n- صوت فقاقيع في الصدر\n- قلق شديد وتعرق\n\n### ⚠️ علاج فوري\n- الجلوس بوضعية منتصبة\n- أكسجين عالي التدفق\n- فوروسيميد 40-80 ملغ وريدي\n- نيتروجليسرين تحت اللسان\n- مورفين 2-4 ملغ وريدي (بحذر)','ar','ESC',10,true),
('red_flags','ruptured_ectopic',ARRAY['انفجار حمل خارجي','نزيف داخلي','صدمة','ألم حوض حاد'],'انفجار الحمل خارج الرحم',E'## 🚨 انفجار الحمل خارج الرحم\n\n### أعراض الانفجار\n- ألم حاد مفاجئ أسفل البطن\n- نزيف مهبلي\n- دوخة وإغماء\n- ألم في الكتف\n- شحوب وتعرق بارد\n\n### ⚠️ طوارئ جراحية فورية\n- خطر وفاة من النزيف الداخلي\n- محاليل + دم فوراً\n- جراحة منظارية أو مفتوحة\n- لا تتأخري أبداً','ar','RCOG',10,true),
('red_flags','severe_preeclampsia',ARRAY['تسمم حمل','ارتفاع ضغط حامل','بروتين بول','صداع حمل','تشنجات حمل'],'تسمم الحمل الشديد',E'## 🚨 تسمم الحمل الشديد\n\n### الأعراض\n- ضغط > 160/110\n- صداع شديد لا يستجيب للمسكنات\n- اضطراب الرؤية (بقع، ومضات)\n- ألم شرسوفي (أعلى البطن)\n- تورم مفاجئ في الوجه\n- بروتين في البول\n\n### ⚠️ خطر الارتعاج (تشنجات)\n- كبريتات المغنيسيوم وريدي\n- خفض الضغط (لابيتالول أو نيفيديبين)\n- الولادة هي العلاج النهائي\n- مراقبة الجنين مستمرة','ar','RCOG/WHO',10,true),
('red_flags','acute_limb_ischemia',ARRAY['نقص تروية طرف','ألم ساق مفاجئ','شحوب طرف','برودة القدم','غياب نبض'],'نقص التروية الحاد للأطراف',E'## 🚨 نقص التروية الحاد للأطراف\n\n### العلامات الستة (6Ps)\n- Pain ألم شديد مفاجئ\n- Pallor شحوب\n- Pulselessness غياب النبض\n- Paresthesia خدر وتنميل\n- Paralysis شلل\n- Perishing cold برودة شديدة\n\n### ⚠️ طوارئ وعائية\n- خطر فقدان الطرف خلال 6 ساعات\n- مميعات دم فورية (هيبارين)\n- جراحة أو قسطرة عاجلة\n- مسكنات قوية','ar','ESVS',10,true),
('red_flags','diabetic_emergency',ARRAY['غيبوبة سكر','ارتفاع سكر شديد','نقص سكر شديد','حالة سكري طارئة'],'الطوارئ السكرية',E'## 🚨 طوارئ مرض السكري\n\n### هبوط السكر الشديد (<54 ملغ/دل)\n- فقدان الوعي أو تشنجات\n- جلوكاجون عضلي + دكستروز وريدي\n\n### ارتفاع السكر الشديد (>600)\n- جفاف شديد + تشوش\n- حالة فرط أسمولية → محاليل + أنسولين\n\n### متى تذهب للطوارئ\n- سكر < 54 مع فقدان وعي\n- سكر > 300 مع قيء\n- سكر > 600\n- أعراض DKA (تنفس سريع، رائحة فواكه)','ar','ADA',10,true),
('red_flags','postpartum_hemorrhage',ARRAY['نزيف بعد الولادة','نزيف رحمي','ونى رحمي','صدمة بعد ولادة'],'النزيف بعد الولادة',E'## 🚨 النزيف بعد الولادة\n\n### التعريف\n- فقدان > 500 مل بعد ولادة طبيعية\n- فقدان > 1000 مل بعد قيصرية\n\n### الأسباب (4 Ts)\n- Tone: ونى الرحم (الأشيع)\n- Tissue: بقايا مشيمة\n- Trauma: تمزقات\n- Thrombin: اضطراب تخثر\n\n### ⚠️ علاج فوري\n- تدليك الرحم\n- أوكسيتوسين 40 وحدة بالتسريب\n- محاليل + دم\n- ميزوبروستول 800 ميكروغرام شرجي\n- جراحة إذا لم يتوقف','ar','WHO',10,true),
('red_flags','spinal_cord_injury',ARRAY['إصابة نخاع شوكي','شلل','إصابة عمود فقري','حادث','سقوط'],'إصابة النخاع الشوكي',E'## 🚨 إصابة النخاع الشوكي\n\n### الاشتباه عند\n- حادث سيارة أو سقوط من ارتفاع\n- ألم رقبة أو ظهر بعد إصابة\n- خدر أو ضعف في الأطراف\n- فقدان السيطرة على المثانة/الأمعاء\n\n### ⚠️ قواعد ذهبية\n- لا تحرك المصاب\n- ثبت الرقبة بطوق عنقي\n- انقله على لوح صلب\n- كل حركة خاطئة قد تسبب شللاً دائماً','ar','ATLS',10,true),
('red_flags','acute_pancreatitis',ARRAY['التهاب بنكرياس','ألم شرسوفي','ألم ينتشر للظهر','قيء شديد'],'التهاب البنكرياس الحاد',E'## 🚨 التهاب البنكرياس الحاد\n\n### الأعراض\n- ألم شرسوفي شديد ينتشر للظهر\n- يخف بالانحناء للأمام\n- غثيان وقيء شديد\n- انتفاخ البطن\n- حمى\n\n### الأسباب\n- حصوات المرارة (الأشيع)\n- الكحول\n- أدوية\n\n### ⚠️ يحتاج دخول مستشفى\n- صيام + محاليل وريدية\n- مسكنات (لا مورفين)\n- مراقبة المضاعفات\n- ليباز أو أميليز مرتفع 3 أضعاف','ar','ACG',10,true),
('red_flags','upper_gi_bleed',ARRAY['نزيف معدي','قيء دموي','براز أسود','تقيؤ دم','ميلينا'],'نزيف الجهاز الهضمي العلوي',E'## 🚨 نزيف الجهاز الهضمي العلوي\n\n### الأعراض\n- قيء دموي أو لون القهوة\n- براز أسود قطراني (ميلينا)\n- دوخة وضعف\n- تسارع النبض\n\n### الأسباب\n- قرحة معدية/اثني عشرية\n- دوالي المريء\n- تمزق مالوري-فايس\n\n### ⚠️ تصرف فوراً\n- محاليل وريدية + نقل دم\n- أوميبرازول 80 ملغ وريدي\n- منظار علوي خلال 24 ساعة\n- إيقاف مميعات الدم والمسكنات','ar','BSG',10,true),
('red_flags','cardiac_tamponade',ARRAY['اندحاس قلبي','انصباب تأموري','بيك ثلاثي','ضيق تنفس','هبوط ضغط'],'الاندحاس القلبي',E'## 🚨 الاندحاس القلبي\n\n### ثلاثي بيك\n- هبوط ضغط الدم\n- انتفاخ أوردة الرقبة\n- أصوات قلب مكتومة\n\n### أعراض أخرى\n- ضيق تنفس متصاعد\n- تسارع القلب\n- نبض متناقض\n\n### ⚠️ طوارئ قلبية\n- بزل التأمور الإسعافي\n- محاليل وريدية لرفع الضغط\n- لا تعطِ مدرات البول\n- إيكو عاجل + جراحة قلب','ar','AHA',10,true),
('red_flags','bowel_obstruction',ARRAY['انسداد أمعاء','قيء أخضر','إمساك تام','انتفاخ بطن','مغص شديد'],'انسداد الأمعاء',E'## 🚨 انسداد الأمعاء\n\n### الأعراض\n- ألم بطني ماغص (موجات)\n- قيء (أخضر = علوي)\n- إمساك تام (لا براز ولا غازات)\n- انتفاخ البطن\n- أصوات أمعاء عالية ثم صامتة\n\n### الأسباب\n- التصاقات بعد جراحة سابقة\n- فتق مختنق\n- أورام\n- انغلاف (أطفال)\n\n### ⚠️ يحتاج تقييم جراحي عاجل\n- أنبوب أنفي معدي\n- محاليل وريدية\n- أشعة بطن واقفاً\n- جراحة إذا اختناق أو ثقب','ar','WHO',10,true),
('red_flags','febrile_seizure',ARRAY['تشنج حراري','تشنجات أطفال','حمى وتشنج','صرع حراري'],'التشنجات الحرارية عند الأطفال',E'## 🚨 التشنجات الحرارية عند الأطفال\n\n### التعريف\n- تشنجات مع حمى عند أطفال 6 أشهر - 5 سنوات\n- بدون عدوى في الجهاز العصبي\n\n### أثناء التشنج\n- ضع الطفل على جنبه\n- لا تضع شيئاً في فمه\n- سجل مدة التشنج\n- أعطِ خافض حرارة بعد التوقف\n\n### ⚠️ اذهب للطوارئ إذا\n- التشنج > 5 دقائق\n- تشنج ثانٍ في نفس المرض\n- عمر < 6 أشهر\n- عدم استعادة الوعي\n- تصلب رقبة','ar','AAP',10,true),
('red_flags','thyroid_storm',ARRAY['عاصفة درقية','فرط درقية شديد','تسارع قلب شديد','حمى','هياج'],'العاصفة الدرقية',E'## 🚨 العاصفة الدرقية\n\n### الأعراض\n- حمى شديدة > 40°C\n- تسارع قلب > 140/دقيقة\n- هياج وقلق شديد\n- إسهال وقيء\n- رجفان أذيني\n- فشل قلبي\n\n### ⚠️ طوارئ غدد صماء\n- نسبة وفاة 10-30%\n- PTU أو كاربيمازول جرعة عالية\n- بيتا بلوكر (بروبرانولول)\n- هيدروكورتيزون وريدي\n- يود بعد ساعة من PTU\n- تبريد (لا أسبرين)','ar','ATA',10,true),
('red_flags','addisonian_crisis',ARRAY['أزمة أديسونية','قصور كظري','هبوط ضغط شديد','نقص كورتيزول'],'أزمة قصور الكظر',E'## 🚨 أزمة قصور الكظر (أديسونية)\n\n### الأعراض\n- هبوط ضغط شديد لا يستجيب للمحاليل\n- ضعف شديد وإرهاق\n- ألم بطن + غثيان + قيء\n- جفاف شديد\n- تشوش ذهني\n- فرط تصبغ الجلد\n\n### ⚠️ علاج فوري\n- هيدروكورتيزون 100 ملغ وريدي فوراً\n- محاليل ملحية وريدية بسرعة\n- دكستروز إذا هبوط سكر\n- لا تتأخر بانتظار الفحوصات','ar','ES',10,true),
('red_flags','malignant_hyperthermia',ARRAY['ارتفاع حرارة خبيث','تخدير','تصلب عضلي','تسارع قلب'],'ارتفاع الحرارة الخبيث',E'## 🚨 ارتفاع الحرارة الخبيث\n\n### يحدث أثناء التخدير العام\n- ارتفاع حرارة سريع > 40°C\n- تصلب عضلي شامل\n- تسارع القلب\n- ارتفاع CO2\n- لون البول داكن (رابدوميوليزز)\n\n### ⚠️ طوارئ تخدير\n- إيقاف المخدر الاستنشاقي فوراً\n- دانترولين 2.5 ملغ/كغ وريدي\n- تبريد فعال\n- محاليل باردة وريدية\n- مراقبة البوتاسيوم والكلى','ar','MHAUS',10,true);
